sql:
SELECT AVG(CAST(REPLACE(host_response_rate, '%', '') AS REAL) / 100) AS average_response_rate
FROM hosts
WHERE host_id = 123;

SELECT COUNT(*)
FROM instant_bookings
WHERE is_instant_bookable = 1;

SELECT DISTINCT guest_language AS unique_languages
FROM guests
ORDER BY guest_language;

SELECT COUNT(host_id) AS number_of_hosts
FROM hosts
WHERE CAST(REPLACE(host_response_rate, '%', '') AS REAL) > 80;

SELECT host_id, host_response_rate
FROM hosts
ORDER BY CAST(SUBSTR(host_response_rate, 1, LENGTH(host_response_rate) - 1) AS REAL) DESC;

external_knowledge:
- "bustling accommodations" refers to listings that have above-average guest counts;
- "higher crowd than average" means more guests than the mean guest count across all listings;
- "hosts" are considered based on an average of their listings’ guest counts.
